var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"갑자기 나타나서 뭐 하는 거야? 제삼자는 빠지라고!","JPN":"突然現れて何なの！？　第三者は引っ込んでなさいよ！","ENG":"Mind your own business, okay?! Stay out of this!","TWN":"突然冒出來是要幹嘛？局外人就別攪和了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"쯔쯧! 그라믄 안 돼 그라믄.","JPN":"ちっちっ……そんなんあかん、そんなん。","ENG":"Tsk, tsk! That ain't right.","TWN":"嘖嘖！這可不行，一點都不行。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_LEGACY_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"퀘스트는 서로 사이좋게 해야지, 싸우기나 하고 그라믄 안 돼.","JPN":"クエストはケンカせんと、互いに仲ようやらなあかんねん。","ENG":"Y'all should be workin' together to beat the quest, not fightin' each other.","TWN":"任務要和和氣氣地完成，不可以吵架。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_LEGACY_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그러니까 이 미리네 님한테 싱겁게 패배하는 거 아니겠나?","JPN":"そんなんやからこのマリ様にあっさり負けるんやで。","ENG":"Ain't that why y'all lost to me, Mi Rinae?","TWN":"所以才會輕易地敗給我宓璃奈吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미리네……? 잠깐, 패배했다고?","JPN":"マリ……？　ちょっと、負けるですって！？","ENG":"Mi Rinae...? Hold on, what do you mean we lost?","TWN":"宓璃奈……？等等，輸了？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"스카이 녀석들을 어쩐거야?!","JPN":"スカイたちはどうしたの！？","ENG":"What did you do to Sky and the others?!","TWN":"你對絲凱她們做了什麼？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"얘, 얘는 구해줬더니 보따리 내놓으라 카네?","JPN":"こ、この子……助けてやったのに恩知らずやなあ。","ENG":"I just saved their butts and all I get in return is ya shouting at my face?","TWN":"喂，我都救了這傢伙，還要我交出寶箱？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"진정해요 선배! 미리네 씨는 저흴 구해주신 거예요!","JPN":"落ち着いて、先輩！　マリさんは私たちを助けてくれたんです！","ENG":"Calm down, Naielle! Mi Rinae's the one who saved us!","TWN":"冷靜點，前輩！宓璃奈姊姊是來救我們的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"보물 상자가 갑자기 괴물로 변할 줄은 몰랐어요…….","JPN":"宝箱が急に化け物に変身するとは思わなかった……","ENG":"We didn't know the chest would suddenly transform into a monster...","TWN":"沒想到寶箱突然變成了怪物……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그럼 설마…….","JPN":"じゃ、じゃあまさか……","ENG":"Th-then...","TWN":"那，那難道……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 뭐 그렇게 됐다.","JPN":"あはは、まあ。そんなもんや。","ENG":"Ah hah hah. Well, ain't that the truth.","TWN":"哈哈哈，反正就是這樣的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아! 뺏은 건 아니고, 아까 그 미믹한텐 아무것도 안 나왔다.","JPN":"あ！　奪ったんちゃうで。さっきのミミックからは何も出んかった。","ENG":"Oh, and by the way! I didn't steal nothin'. The mimic didn't even drop a thing.","TWN":"啊！不是我拿的，剛才那個怪物什麼都沒掉。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"어쨌든 이번 퀘스트의 승자는 이 미리네가 됐다 이 말이다.","JPN":"とにかく、今回のクエストの勝者はこのマリ様っちゅうわけや。","ENG":"Anywho, the winner of this quest is me, Mi Rinae.","TWN":"總之，這次任務的贏家是我，宓璃奈。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이렇게 허무하게……?","JPN":"こ、こんなにあっけなく……","ENG":"S-so this is how it ends...?","TWN":"這，這麼空虛……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 너무 그렇게 상심하지 마라.","JPN":"あはは、そんなへこまんといて。","ENG":"Ah hah hah! Now, don't be so discouraged.","TWN":"哈哈哈，不要那麼傷心。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니 아카데미 학생 맞제? 이름이 뭐꼬?","JPN":"あんた、アカデミーの生徒やろ？　名前なんて言うん？","ENG":"You're from the Academy, aren't ya? What's your name?","TWN":"你是學院的學生吧？你叫什麼名字？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 엘리트인 내 이름을 모르는 게 말이 돼?","JPN":"ふん、エリートの私の名前を知らないなんてあり得ないんだけど。","ENG":"Hmph. How can anyone not know an elite like me?","TWN":"哼，不知道我這個精英的名字，怎麼可能？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"엘리트……?","JPN":"エリート……？","ENG":"Elite...?","TWN":"精英……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아~ 니 설마 나이엘이가? 나이엘 블루스틸! 맞제?!","JPN":"ああ～まさかあんたナイエル？　ナイエル・ブルースチール！　そうやろ？","ENG":"Oh! You're the Naielle gal, ain't ya? Naielle Bluesteel! Right?!","TWN":"啊～你該不會是奈爾吧？奈爾·布魯斯提爾，對吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하핫, 거 봐! 역시 알고 있었잖아!","JPN":"ふん！　ほら、やっぱり知ってるじゃない！","ENG":"Haha! So you do know who I am!","TWN":"哈哈，你看！果然知道吧！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……아니, 어떻게 알고 있는 거야?","JPN":"……って、どうして知ってるのよ？","ENG":"...Wait. How did you know?","TWN":"……不，不對，你是怎麼知道的？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"네가 그 나이엘이구나! 보라한테 말 많이 들었다!","JPN":"あんたがあのナイエルか～！　シホから話は聞いたで！","ENG":"We finally meet in person, Naielle! I heard a lot 'bout ya from Bora!","TWN":"你就是那個奈爾啊！聽寶拉說了很多關於你的事！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"우리 나름 구면인데, 내 못 알아보긋나?","JPN":"ウチら、実は初対面ちゃうけど、ウチのこと知らへん？","ENG":"We've met before; can't ya recognize me?","TWN":"我們以前見過的，你不記得我了嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야, 당신 그 낙하산이랑 아는 사이였어? 난 당신 본 기억 없다고!","JPN":"何よ、あんたあのコネ教師と知り合い？　私は見覚えないんだけど。","ENG":"Huh? You're friends with her? I've never seen you in my life!","TWN":"什麼，你和那個空降部隊認識？我可不記得見過你！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"흠…… 그래?\xA0","JPN":"ふーん……そう？\xA0","ENG":"Hmm... Is that so?\xA0","TWN":"嗯……是嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그럼 오락실의 랭커★스타라이트! 이러면 알긋제?","JPN":"じゃ、ゲームセンターのランカー★スターライト！　って言うたらわかるかな？","ENG":"Then, how 'bout the arcade's Ranker★Starlight! Does that ring a bell?","TWN":"遊藝場的高手★星光！這樣就知道了吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};